import mysql.connector

def load_data_infile(user, password, host, database, table_name, file_name):
    try:
        # Connect to the MySQL Database
        db = mysql.connector.connect(
          user = user,
          password = password,
          host = host,
          database = database
        )
        
        # Create a cursor object
        cursor = db.cursor()
        
        # Enable local_infile 
        cursor.execute("SET GLOBAL local_infile = 1;")
        
        # Load data infile query
        query = "LOAD DATA INFILE '{}' INTO TABLE {}".format(file_name, table_name)
        
        # Execute the query
        cursor.execute(query)
        
        # Commit the transaction
        db.commit()
        
    except mysql.connector.Error as e:
        print("Error: ", e)

    finally:
        if (db.is_connected()):
            cursor.close()
            db.close()

